section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/dx-friction-log-format.json",
  "title": "DX Friction Log Format",
  "type": "object",
  "required": [
    "artefact_id",
    "rows",
    "triage_cadence",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "rows": {
      "type": "array",
      "minItems": 1,
      "description": "list of {timestamp, surface, severity, description, proposed_fix, status, triaged_at}"
    },
    "triage_cadence": {
      "type": "string",
      "description": "ISO-8601 duration between triages (e.g. P7D)"
    }
  },
  "additionalProperties": false
}
